request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?model ?created ?orgName WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task bbo:name ?taskName .
  FILTER(CONTAINS(LCASE(STR(?taskName)), LCASE("credetnials")))

  ?task tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    OPTIONAL { ?org rdfs:label ?orgName . }
  }
}
ORDER BY DESC(?created)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?model ?created ?orgName ?taskName WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task bbo:name ?taskName .

  FILTER(
    CONTAINS(LCASE(STR(?taskName)), LCASE("credentials")) ||
    CONTAINS(LCASE(STR(?taskName)), LCASE("credetnials")) ||
    CONTAINS(LCASE(STR(?taskName)), LCASE("creditn"))
  )

  ?task tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL {
    ?model tai:belongsTo ?org .
    OPTIONAL { ?org rdfs:label ?orgName . }
  }
}
ORDER BY DESC(?created)
LIMIT 25
